SELECT 1 AS Kolejnosc, 'TwG_GIDTyp'            AS CDN_Pole, 'Identyfikator grupy lub elementu'         AS Opis_w_dokumentacji, '-16, 16' AS Przykladowe_wartosci,  '-'                 AS Alias_w_widoku,  'Filtr techniczny (GIDTyp=16 bridge)'      AS Transformacja, 'Nie' AS Uwzglednic, 'Stała techniczna — filtr WHERE'         AS Uzasadnienie, '' AS Komentarz_Usera UNION ALL
