SELECT 7, 'TwG_GrONumer',           'Identyfikator grupy nadrzędnej',           '72, 5472, 49',          'ID_Grupy',          'Klucz grupy ogólnej (GIDTyp=-16)',         'Tak',  'FK do definicji grupy',                 '' UNION ALL
SELECT 8, 'TwG_GrOLp',              'Identyfikator grupy nadrzędnej',           '0',                     '-',                 'Stała 0',                                 'Nie',  'GIDLp zawsze pomijamy',                 '' UNION ALL
