SELECT 10,'TwG_Nazwa',              'Nazwa grupy lub elementu',                 'Choinka CH 10',         'Nazwa_Towaru',      'JOIN CDN.TwrKarty → Twr_Nazwa',           'Tak',  'Nazwa towaru — JOIN preferred',          '' UNION ALL
