SELECT 15,'[JOIN] Twr_Nazwa',       '',                                          '',                     'Nazwa_Towaru',      'CDN.TwrKarty.Twr_Nazwa',                  'Tak',  'Nazwa towaru ze źródła',                '' UNION ALL
